import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { TaskService } from '../../services/task.service';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
@Component({
  selector: 'app-task-form',
  templateUrl: './task-form.component.html',
  styleUrls: ['./task-form.component.css'],
})
export class TaskFormComponent {
  taskForm: FormGroup;

  constructor(
    private formBuilder: FormBuilder,
    private taskService: TaskService,
    private router: Router,
    private http: HttpClient
  ) {
    this.taskForm = this.formBuilder.group({
      title: ['', Validators.required],
      completed: [false],
      category: [''],
      dueDate: [''],
    });
  }

  ngOnInit(): void {
    // Additional initialization if needed
  }

  // addTask(): void {
  //   console.log(this.taskForm.value);
  //   if (this.taskForm.valid) {
  //     this.taskService.addTask(this.taskForm.value).subscribe(() => {
  //       // Optional: Add logic after task is added, e.g., clear form or navigate to task listing
  //     });
  //   }
  // }
  addTask() {
    console.log(this.taskForm.value);
    this.http
      .post<any>('http://localhost:3000/tasks', this.taskForm.value)
      .subscribe(
        (res) => {
          alert('added successfull');
          this.taskForm.reset();
          this.router.navigate(['task-list']);
        },
        (err) => {
          alert('something is wrong');
        }
      );
  }
}
<form [formGroup]="taskForm" (ngSubmit)="addTask()">
  <div>
    <label>Title:</label>
    <input formControlName="title" type="text" />
  </div>
  <div>
    <label>Completed:</label>
    <input formControlName="completed" type="checkbox" />
  </div>
  <div>
    <label>Category:</label>
    <input formControlName="category" type="text" />
  </div>
  <div>
    <label>Due Date:</label>
    <input formControlName="dueDate" type="date" />
  </div>
  <div>
    <button type="submit">Add Task</button>
  </div>
</form>
